+            })
+        );
+        assert_eq!(
+            suggested[1],
+            serde_json::json!({
+                "tool": "request_contact",
+                "arguments": {
+                    "project_key": project_key,
+                    "from_agent": "GreenCastle",
+                    "to_agent": "BlueLake",
+                    "ttl_seconds": ttl_seconds,
+                }
+            })
+        );
+    });
